import{_ as r,c as l,o as a,aN as o}from"./chunks/framework.DXgs1r1w.js";const g=JSON.parse('{"title":"HTTP 版本","description":"","frontmatter":{"date":"2024-09-06T09:30:00.000Z","title":"HTTP 版本","outline":"deep","lastUpdated":true,"footer":true,"permalink":"/pages/e7f9a2","categories":["Linux","计算机网络","HTTP"]},"headers":[],"relativePath":"Linux/计算机网络/HTTP/HTTP版本.md","filePath":"Linux/计算机网络/HTTP/HTTP版本.md","lastUpdated":1784195928000}'),d={name:"Linux/计算机网络/HTTP/HTTP版本.md"};function i(e,t,n,s,T,h){return a(),l("div",null,[...t[0]||(t[0]=[o(`<h1 id="http-版本" tabindex="-1">HTTP 版本 <a class="header-anchor" href="#http-版本" aria-label="Permalink to &quot;HTTP 版本&quot;">​</a></h1><h2 id="一、总览" tabindex="-1">一、总览 <a class="header-anchor" href="#一、总览" aria-label="Permalink to &quot;一、总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>发布年份</th><th>传输层</th><th>核心变化</th></tr></thead><tbody><tr><td>HTTP/0.9</td><td>1991</td><td>TCP</td><td>仅 GET，无头部，纯文本</td></tr><tr><td>HTTP/1.0</td><td>1996</td><td>TCP</td><td>引入请求/响应头、状态码</td></tr><tr><td>HTTP/1.1</td><td>1997</td><td>TCP</td><td>持久连接、管道化、Host 头</td></tr><tr><td>HTTP/2</td><td>2015</td><td>TCP</td><td>二进制分帧、多路复用、头部压缩</td></tr><tr><td>HTTP/3</td><td>2022</td><td>QUIC(UDP)</td><td>解决队头阻塞、连接迁移</td></tr></tbody></table><blockquote><p>本文重点对比 <strong>HTTP/1.1、HTTP/2、HTTP/3</strong> 三者的特性区别与优化提升。</p></blockquote><hr><h2 id="二、http-1-1" tabindex="-1">二、HTTP/1.1 <a class="header-anchor" href="#二、http-1-1" aria-label="Permalink to &quot;二、HTTP/1.1&quot;">​</a></h2><p>HTTP/1.1 是长期以来的主流版本，在 HTTP/1.0 基础上做了大量增强。</p><h3 id="主要特性" tabindex="-1">主要特性 <a class="header-anchor" href="#主要特性" aria-label="Permalink to &quot;主要特性&quot;">​</a></h3><ul><li><strong>持久连接（Keep-Alive）</strong>：默认 <code>Connection: keep-alive</code>，多个请求复用同一条 TCP 连接，避免频繁三次握手和慢启动开销。</li><li><strong>管线化（Pipelining）</strong>：理论上可一次性发送多个请求，但<strong>响应必须按序返回</strong>，存在<strong>队头阻塞（Head-of-Line Blocking）</strong>，且多数服务器/代理支持有限，实际很少启用。</li><li><strong>分块传输（Chunked）</strong>：<code>Transfer-Encoding: chunked</code> 支持流式传输，不必提前知道内容长度。</li><li><strong>Host 头（必需）</strong>：支持虚拟主机，一台服务器可托管多个域名。</li><li><strong>缓存控制增强</strong>：引入 <code>Cache-Control</code>、<code>ETag</code>、<code>If-None-Match</code> 等更精细的缓存机制。</li><li><strong>断点续传</strong>：<code>Range</code> 请求支持部分内容获取。</li><li><strong>新增方法</strong>：PUT、DELETE、OPTIONS、PATCH 等。</li></ul><h3 id="主要问题-被后续版本优化" tabindex="-1">主要问题（被后续版本优化） <a class="header-anchor" href="#主要问题-被后续版本优化" aria-label="Permalink to &quot;主要问题（被后续版本优化）&quot;">​</a></h3><ol><li><strong>队头阻塞</strong>：虽然连接可复用，但同一条连接上请求必须串行等待，前一个响应慢会阻塞后面所有请求。</li><li><strong>并发受限</strong>：浏览器对同一域名的并行 TCP 连接数有限（通常 6 个），高并发时仍需多条连接。</li><li><strong>头部冗余</strong>：每次请求都重复发送大量相似头部（Cookie、User-Agent 等），浪费带宽。</li><li><strong>文本协议</strong>：解析效率低，易出错。</li></ol><hr><h2 id="三、http-2" tabindex="-1">三、HTTP/2 <a class="header-anchor" href="#三、http-2" aria-label="Permalink to &quot;三、HTTP/2&quot;">​</a></h2><p>HTTP/2 于 2015 年发布（基于 Google 的 SPDY 协议），<strong>语义与 HTTP/1.1 完全兼容</strong>（方法、状态码、头部字段不变），但<strong>传输方式彻底重构</strong>。</p><h3 id="核心优化" tabindex="-1">核心优化 <a class="header-anchor" href="#核心优化" aria-label="Permalink to &quot;核心优化&quot;">​</a></h3><ol><li><p><strong>二进制分帧（Binary Framing）</strong></p><ul><li>不再是人类可读的文本，而是把数据拆成二进制<strong>帧（Frame）</strong>，解析高效、不易出错。</li><li>帧是最小传输单位，归属于某个<strong>流（Stream）</strong>。</li></ul></li><li><p><strong>多路复用（Multiplexing）</strong> —— 最核心的改进</p><ul><li>在<strong>单条 TCP 连接</strong>上并行传输多个请求/响应。</li><li>每个请求是一个独立的<strong>流（Stream）</strong>，带有流 ID，帧可交错发送，接收端按 ID 重组。</li><li>彻底解决 HTTP/1.1 的应用层队头阻塞，同时减少 TCP 连接数。</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP/1.1:  连接1: [请求A]→[响应A] [请求B]→[响应B]   (串行)</span></span>
<span class="line"><span>HTTP/2:    连接1:  流1: A帧A帧   流2: B帧B帧B帧    (交错并行)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p><strong>头部压缩（HPACK）</strong></p><ul><li>维护客户端/服务器两张<strong>静态+动态字典表</strong>，重复头部只传索引。</li><li>大幅降低头部体积（常见场景下头部可压缩 80%~90%）。</li></ul></li><li><p><strong>服务器推送（Server Push）</strong></p><ul><li>服务器可主动把客户端「可能需要的资源」推过去（如 HTML 引用的 CSS/JS），减少往返。</li><li>实际使用中因缓存、带宽控制等问题效果有限，部分浏览器已弃用。</li></ul></li><li><p><strong>请求优先级（Stream Priority）</strong></p><ul><li>可给流设置优先级，重要资源（如 CSS）优先传输。</li></ul></li></ol><h3 id="仍存在的局限" tabindex="-1">仍存在的局限 <a class="header-anchor" href="#仍存在的局限" aria-label="Permalink to &quot;仍存在的局限&quot;">​</a></h3><ul><li><strong>TCP 层的队头阻塞</strong>：HTTP/2 的多路复用建立在<strong>单条 TCP 连接</strong>上。一旦 TCP 层某个包丢失，整个连接的所有流都要等待重传，这就是 <strong>TCP 级队头阻塞</strong>。</li><li>握手延迟：基于 TCP + TLS，仍需多次往返才能建连。</li></ul><hr><h2 id="四、http-3" tabindex="-1">四、HTTP/3 <a class="header-anchor" href="#四、http-3" aria-label="Permalink to &quot;四、HTTP/3&quot;">​</a></h2><p>HTTP/3 于 2022 年正式标准化（RFC 9114），最大的改变是<strong>把传输层从 TCP 换成了基于 UDP 的 QUIC 协议</strong>。</p><h3 id="为什么会诞生-http-3" tabindex="-1">为什么会诞生 HTTP/3？ <a class="header-anchor" href="#为什么会诞生-http-3" aria-label="Permalink to &quot;为什么会诞生 HTTP/3？&quot;">​</a></h3><p>HTTP/2 的瓶颈在 TCP：单连接上的多路复用，一旦丢包整条连接阻塞。而 TCP 的队头阻塞无法在应用层修复，只能换传输层。QUIC 在 UDP 之上重建了可靠的、多路复用的传输能力。</p><h3 id="核心优化-1" tabindex="-1">核心优化 <a class="header-anchor" href="#核心优化-1" aria-label="Permalink to &quot;核心优化&quot;">​</a></h3><ol><li><p><strong>基于 QUIC（UDP）</strong></p><ul><li>QUIC 在用户态实现可靠传输，多个流独立，单个流丢包只阻塞该流，<strong>彻底解决 TCP 级队头阻塞</strong>。</li></ul></li><li><p><strong>0-RTT / 1-RTT 建连</strong></p><ul><li>首次连接 1-RTT（QUIC + TLS 合并握手）。</li><li>后续重连可 <strong>0-RTT</strong> 直接发数据，相比 TCP+TLS 的 2~3 RTT 大幅降低延迟。</li></ul></li><li><p><strong>连接迁移（Connection Migration）</strong></p><ul><li>用 <strong>Connection ID</strong> 标识连接，而不是靠「IP + 端口」四元组。</li><li>切换网络（如 Wi-Fi 切 4G）时连接不中断，无需重连。</li></ul></li><li><p><strong>内置 TLS 1.3</strong></p><ul><li>QUIC 将加密层与传输层融合，所有数据默认加密，更安全。</li></ul></li><li><p><strong>改进的拥塞控制与丢包恢复</strong></p><ul><li>QUIC 在用户态实现，更新迭代更快，拥塞控制算法可灵活替换。</li></ul></li></ol><h3 id="代价与挑战" tabindex="-1">代价与挑战 <a class="header-anchor" href="#代价与挑战" aria-label="Permalink to &quot;代价与挑战&quot;">​</a></h3><ul><li>UDP 可能被部分网络/防火墙限制或限速。</li><li>内核无法像 TCP 那样深度优化，实现复杂度集中在用户态。</li><li>加密解密开销上移到用户态。</li></ul><hr><h2 id="五、三版本对比总表" tabindex="-1">五、三版本对比总表 <a class="header-anchor" href="#五、三版本对比总表" aria-label="Permalink to &quot;五、三版本对比总表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>HTTP/1.1</th><th>HTTP/2</th><th>HTTP/3</th></tr></thead><tbody><tr><td>传输层</td><td>TCP</td><td>TCP</td><td>QUIC（基于 UDP）</td></tr><tr><td>协议格式</td><td>文本</td><td>二进制帧</td><td>二进制帧</td></tr><tr><td>并发模型</td><td>多连接 + 管线化（受限）</td><td>单连接多路复用</td><td>单连接多路复用</td></tr><tr><td>队头阻塞</td><td>应用层阻塞</td><td>解决应用层，存在 TCP 层阻塞</td><td>彻底解决（流级独立）</td></tr><tr><td>头部</td><td>明文重复传输</td><td>HPACK 压缩</td><td>QPACK 压缩（类似 HPACK）</td></tr><tr><td>建连延迟</td><td>TCP+TLS 2~3 RTT</td><td>同 HTTP/1.1</td><td>1-RTT / 0-RTT 重连</td></tr><tr><td>连接迁移</td><td>不支持（IP 变即断）</td><td>不支持</td><td>支持（Connection ID）</td></tr><tr><td>服务器推送</td><td>无</td><td>有（已渐弃用）</td><td>已移除</td></tr><tr><td>安全性</td><td>可选 HTTPS</td><td>普遍 HTTPS</td><td>强制内置 TLS 1.3</td></tr><tr><td>兼容性</td><td>最广泛</td><td>语义兼容 1.1</td><td>需客户端/服务端支持</td></tr></tbody></table><hr><h2 id="六、演进脉络一句话总结" tabindex="-1">六、演进脉络一句话总结 <a class="header-anchor" href="#六、演进脉络一句话总结" aria-label="Permalink to &quot;六、演进脉络一句话总结&quot;">​</a></h2><ul><li><strong>HTTP/1.1 → HTTP/2</strong>：从「文本 + 多连接」升级为「二进制 + 单连接多路复用 + 头部压缩」，解决了应用层队头阻塞和头部冗余。</li><li><strong>HTTP/2 → HTTP/3</strong>：从「TCP」换到「UDP + QUIC」，解决了 TCP 层队头阻塞，并带来 0-RTT 建连和连接迁移能力，核心目标是<strong>降低延迟、提升弱网/移动网络体验</strong>。</li></ul><blockquote><p>选择建议：现代 Web 站点应优先启用 HTTP/2（兼容性最好）；面向移动端、弱网或延迟敏感场景可进一步启用 HTTP/3；二者通常通过 CDN/反向代理（如 Nginx、Cloudflare）开启，对业务代码透明。</p></blockquote>`,34)])])}const u=r(d,[["render",i]]);export{g as __pageData,u as default};
